parameters.text:
=Classify the following support ticket and return a JSON response.

Ticket ID: {{ $json.ticketId }}
Subject: {{ $json.subject }}
Body: {{ $json.body }}

Classify into exactly one category: billing, technical, sales, or general.
Rate urgency as: low, normal, or urgent.
Provide a confidence score between 0 and 1.
Write a brief summary (max 100 words).

Respond ONLY with valid JSON in this exact format:
{
  "category": "one of: billing, technical, sales, general",
  "urgency": "one of: low, normal, urgent",
  "confidence": 0.95,
  "summary": "Brief summary here"
}

parameters.jsCode:
// Parse and validate the AI output
const raw = $input.first().json;
let parsed;

// Try to parse from the AI output
try {
  const text = typeof raw.output === 'string' ? raw.output : JSON.stringify(raw.output);
  // Extract JSON from potential markdown code blocks
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(jsonMatch ? jsonMatch[0] : text);
} catch (e) {
  return {
    json: {
      isValid: false,
      validationErrors: ['Failed to parse AI output as JSON: ' + e.message],
      rawOutput: raw.output,
      retryCount: (raw.retryCount || 0) + 1
    }
  };
}

// Semantic validation
const validCategories = ['billing', 'technical', 'sales', 'general'];
const validUrgencies = ['low', 'normal', 'urgent'];
const errors = [];

if (!validCategories.includes(parsed.category)) {
  errors.push('Invalid category: ' + parsed.category);
}
if (!validUrgencies.includes(parsed.urgency)) {
  errors.push('Invalid urgency: ' + parsed.urgency);
}
if (typeof parsed.confidence !== 'number' || parsed.confidence < 0 || parsed.confidence > 1) {
  errors.push('Confidence must be a number between 0 and 1, got: ' + parsed.confidence);
}
if (!parsed.summary || parsed.summary.length > 500) {
  errors.push('Summary missing or exceeds 500 characters');
}

return {
  json: {
    ...parsed,
    isValid: errors.length === 0,
    validationErrors: errors
  }
};
